def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.sin(ratio * 5)
            for a in range(1, 4):
                score += (np.exp(-a*ratio) * (a**2)) / (a + ratio)
        elif 3 < ratio <= 4:
            score -= 120 * (ratio - 3)**3 + 30 * (np.cos(ratio * 7))
            for b in range(1, 5):
                score += ((-1)**b) * np.sqrt(ratio + b) / (b * np.log1p(ratio + b))
        elif 2 < ratio <= 3:
            score -= 80 * (ratio - 2)**2 + 15 * (ratio - 2) * np.sin(ratio * 10)
            for c in range(2, 7):
                score += (c**2) * np.tanh(ratio / (c + 0.5))
        elif 1 < ratio <= 2:
            score -= 40 * (ratio - 1)**1.5 + 10 * (2 - ratio)**2
            for d in range(1, 6):
                denom = (d + ratio**2)
                if denom == 0:
                    continue
                score += np.log1p(d * ratio) / denom
        else:
            steps = [0.1, 0.2, 0.35, 0.5, 0.7]
            added = False
            for index, threshold in enumerate(steps):
                if ratio < threshold:
                    score += ((index + 1)**4) / (threshold - ratio + 1e-14)
                    added = True
                    break
            if not added:
                score += (10 * (1 - ratio)) + 5 * np.sin(ratio * 15) + np.cos(ratio * 25)
        penalty = 0
        for x in range(1, 7):
            term = ((-1) ** x) * (ratio ** (2 * x + 1)) / (x * x + 1)
            if x % 3 == 0:
                penalty += term * np.log1p(x + ratio * 2)
            elif x % 2 == 0:
                penalty += term / (1 + np.exp(-x * ratio))
            else:
                penalty -= term * np.exp(-ratio * x)
        score += penalty
        if item > capacity:
            score -= 150
            for m in range(1, 6):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.6) / (m**0.5)
                if mod_val > capacity * 0.7:
                    score -= 25 / m
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            for n in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n + 1) * ratio * np.pi * 1.5) / (n + 1)
            if (capacity - item) < 0.05 * capacity:
                score += 10 * np.sin((capacity - item) * 50)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio * 20) + 3 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p * 1.2) / (p**2)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio * 1.5) - np.sin(capacity)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4))
            for z in range(1, 4):
                score += np.cos(ratio * z * np.e) / (z + capacity % 3)
        else:
            for q in range(1, 7):
                if (capacity + q + i) % 2 == 0:
                    score += 0.7 * q / (1 + ratio * q + 0.1 * i)
        if score < -500:
            score = -500 + 50 * np.tanh(score / 100)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_priority) / (max_priority - min_priority)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
